import React from 'react';
import { Carousel } from 'antd';

const contentStyle = {
  position: 'relative',
};

const textOverlayStyle = {
position: 'absolute',
top: '50%',
zIndex: 10,
//   color: '#fff',
textAlign: 'center',
backgroundColor:"red"
};

const imageStyle = {
  width: '100%',
  height: '300px', // Adjusted height
  objectFit: 'cover',
};

const HomeCarousel = () => (
  <Carousel autoplay style={{ margin: '40px' }}>
    <div style={contentStyle}>
      <img src="/carousel1.avif" alt="Carousel 1" style={imageStyle} />
      <div style={textOverlayStyle}>
          WELCOME SHOP NOW
      </div>
    </div>
    <div style={contentStyle}>
      <img src="/carousel2.avif" alt="Carousel 2" style={imageStyle} />
      <div style={textOverlayStyle}>
          WELCOME SHOP NOW
      </div>
    </div>
    <div style={contentStyle}>
      <img src="/carousel3.avif" alt="Carousel 3" style={imageStyle} />
      <div style={textOverlayStyle}>
          WELCOME SHOP NOW
      </div>
    </div>
    <div style={contentStyle}>
      <img src="/carousel4.avif" alt="Carousel 4" style={imageStyle} />
      <div style={textOverlayStyle}>
          WELCOME SHOP NOW
      </div>
    </div>
  </Carousel>
);

export default HomeCarousel;
